const fs = require('fs');

function replaceOnce(text, pattern, replacement, label) {
  const next = text.replace(pattern, replacement);
  if (next === text) throw new Error('Could not patch ' + label);
  return next;
}

let html = fs.readFileSync('index.html', 'utf8');
let workflow = fs.readFileSync('.github/workflows/daily-scan.yml', 'utf8');
let sw = fs.readFileSync('sw.js', 'utf8');

html = html.replace("var CACHE = 'uap-v16-alien-startup';", "var CACHE = 'uap-v17-feed-reading';");
sw = sw.replace("var CACHE = 'uap-v16-alien-startup';", "var CACHE = 'uap-v17-feed-reading';");

html = replaceOnce(html, /  \.badge\.quality \{[^\n]*\}\n/, `  .badge.quality { color: var(--accent); border-color: rgba(0,212,255,.42); background: rgba(0,212,255,.055); cursor: help; }\n  .badge.new { color: #07130f; border-color: rgba(0,255,157,.9); background: var(--accent2); font-weight: 700; }\n  .quality-help {\n    margin: -4px 0 14px;\n    color: #8aa6b3;\n    font-family: 'Share Tech Mono', monospace;\n    font-size: 10px;\n    line-height: 1.55;\n    border-left: 2px solid rgba(0,212,255,.5);\n    padding-left: 10px;\n  }\n  .old-toggle {\n    width: 100%;\n    margin: 6px 0 12px;\n    padding: 11px 12px;\n    border: 1px solid rgba(13,58,92,.9);\n    background: rgba(8,20,32,.82);\n    color: var(--accent);\n    font-family: 'Share Tech Mono', monospace;\n    font-size: 11px;\n    letter-spacing: 1.5px;\n    text-align: left;\n    cursor: pointer;\n  }\n  .old-list { display: flex; flex-direction: column; gap: 12px; }\n  .old-list.collapsed { display: none; }\n`, 'feed CSS');

html = replaceOnce(html, /  <div class="startup-panel-wrap">[\s\S]*?    <div class="loading-bar"><\/div>\n  <\/div>/, `  <div class="startup-panel-wrap">\n    <div class="loading-bar"></div>\n  </div>`, 'startup status panel');
html = html.replace(/\n\s*function setLoadingStatus\(text\) \{[\s\S]*?\n\s*\}/, '');
html = html.replace(/\n\s*setLoadingStatus\([^\n]+\);/g, '');
html = replaceOnce(html, /\n\s*<a class="icon-btn" href="latest-news\.json" title="Rohdaten">\{ \}<\/a>/, '', 'raw data button');
html = replaceOnce(html, /  <div class="notice" id="notice"><\/div>/, `  <div class="quality-help">Wertung: UAP-Relevanz im Titel, offizielle Begriffe oder Institutionen, Anzahl unabhängiger Quellen und Themenbündelung.</div>\n  <div class="notice" id="notice"></div>`, 'quality explanation');

html = replaceOnce(html, /  var articles = \[\];\n/, `  var articles = [];\n  var readIds = loadReadIds();\n\n  function loadReadIds() {\n    try { return JSON.parse(localStorage.getItem('uap_read_ids_v1') || '[]'); } catch(e) { return []; }\n  }\n  function saveReadIds() {\n    try { localStorage.setItem('uap_read_ids_v1', JSON.stringify(readIds.slice(-600))); } catch(e) {}\n  }\n  function isRead(id) { return readIds.indexOf(id) !== -1; }\n  function markRead(id) {\n    if (!id || isRead(id)) return;\n    readIds.push(id);\n    saveReadIds();\n  }\n`, 'read state helpers');

const newRender = `  function render() {\n    if (!feedEl) return;\n    feedEl.innerHTML = '';\n    if (!articles.length) {\n      if (emptyEl) emptyEl.classList.add('show');\n      return;\n    }\n    if (emptyEl) emptyEl.classList.remove('show');\n\n    var fresh = articles.filter(function(a) { return !isRead(a.id); });\n    var old = articles.filter(function(a) { return isRead(a.id); });\n    var oldCollapsed = fresh.length > 0;\n\n    function appendArticle(article, index, isFresh, target) {\n      var sources = allSources(article);\n      var sourceLinks = sources.map(function(s) {\n        var title = s.title && s.title !== article.title ? '<div class="source-headline">' + esc(s.title) + '</div>' : '';\n        var inner = '<div class="source-name">' + esc(s.source || 'Quelle') + '</div>' + title;\n        return s.link ? '<a class="source-link" href="' + esc(s.link) + '" target="_blank" rel="noopener noreferrer">' + inner + '</a>' : '<div class="source-link">' + inner + '</div>';\n      }).join('');\n      var summaryText = article.summary || 'Keine belastbare Zusammenfassung vorhanden.';\n      var qualityTitle = 'Wertung: Relevanz, Quellenanzahl, offizielle Begriffe und Themenbündelung.';\n      var card = document.createElement('article');\n      card.className = 'article-card' + (isFresh ? ' unread' : '');\n      card.innerHTML =\n        '<button class="article-main" type="button" data-index="' + index + '">' +\n          '<div class="badges">' + (isFresh ? '<span class="badge new">NEU</span>' : '') + '<span class="badge sources">' + sources.length + ' Quellen</span><span class="badge quality" title="' + esc(qualityTitle) + '">Wertung ' + esc(article.quality || '-') + '</span></div>' +\n          '<h2 id="title-' + index + '">' + esc(article.title) + '</h2>' +\n          '<div class="meta"><span>' + esc(article.source) + '</span><span>' + esc(fmtDate(article.date)) + '</span></div>' +\n        '</button>' +\n        '<div class="summary" id="summary-' + index + '">' + esc(summaryText) + '</div>' +\n        '<div class="details">' +\n          '<div class="sources-title">Quellen</div>' +\n          '<div class="source-list">' + sourceLinks + '</div>' +\n          '<div class="actions"><button class="translate-btn" type="button" data-translate="' + index + '">Übersetzen</button></div>' +\n        '</div>';\n      target.appendChild(card);\n    }\n\n    fresh.forEach(function(article) { appendArticle(article, articles.indexOf(article), true, feedEl); });\n\n    if (old.length) {\n      var toggle = document.createElement('button');\n      toggle.className = 'old-toggle';\n      toggle.type = 'button';\n      toggle.textContent = (oldCollapsed ? '▸ ' : '▾ ') + 'Ältere Artikel (' + old.length + ')';\n      var oldList = document.createElement('div');\n      oldList.className = 'old-list' + (oldCollapsed ? ' collapsed' : '');\n      toggle.addEventListener('click', function() {\n        oldCollapsed = !oldCollapsed;\n        oldList.classList.toggle('collapsed', oldCollapsed);\n        toggle.textContent = (oldCollapsed ? '▸ ' : '▾ ') + 'Ältere Artikel (' + old.length + ')';\n      });\n      feedEl.appendChild(toggle);\n      feedEl.appendChild(oldList);\n      old.forEach(function(article) { appendArticle(article, articles.indexOf(article), false, oldList); });\n    }\n  }\n  function loadFeed()`;
html = replaceOnce(html, /  function render\(\) \{[\s\S]*?\n  \}\n  function loadFeed\(\)/, newRender, 'render function');

const newClick = `  document.addEventListener('click', function(e) {\n    var main = e.target.closest && e.target.closest('.article-main');\n    if (main) {\n      var index = Number(main.getAttribute('data-index'));\n      var article = articles[index];\n      if (article) {\n        markRead(article.id);\n        main.closest('.article-card').classList.remove('unread');\n        var newBadge = main.querySelector('.badge.new');\n        if (newBadge) newBadge.remove();\n      }\n      var card = main.closest('.article-card');\n      if (card) card.classList.toggle('open');\n      return;\n    }\n    var translate = e.target.closest && e.target.closest('[data-translate]');\n    if (translate) {\n      var index = Number(translate.getAttribute('data-translate'));\n      var article = articles[index];\n      var titleEl = document.getElementById('title-' + index);\n      var summaryEl = document.getElementById('summary-' + index);\n      if (!article || !titleEl || !summaryEl) return;\n      if (article._isTranslated) {\n        titleEl.textContent = article._originalTitle || article.title || '';\n        summaryEl.textContent = article._originalSummary || article.summary || 'Keine belastbare Zusammenfassung vorhanden.';\n        article._isTranslated = false;\n        translate.textContent = 'Übersetzen';\n        return;\n      }\n      var sourceTitle = article._originalTitle || article.title || '';\n      var sourceSummary = article._originalSummary || article.summary || '';\n      article._originalTitle = sourceTitle;\n      article._originalSummary = sourceSummary;\n      translate.disabled = true;\n      translate.textContent = 'Übersetze...';\n      translateText(sourceTitle + '\\n|||\\n' + sourceSummary, 'de')\n        .then(function(text) {\n          var parts = String(text || '').split('|||');\n          titleEl.textContent = (parts[0] || text || sourceTitle).trim();\n          summaryEl.textContent = (parts[1] || sourceSummary || 'Keine belastbare Zusammenfassung vorhanden.').trim();\n          article._isTranslated = true;\n          translate.textContent = 'Original anzeigen';\n        })\n        .catch(function() { translate.textContent = 'Übersetzung fehlgeschlagen'; })\n        .finally(function() { translate.disabled = false; });\n    }\n  });`;
html = replaceOnce(html, /  document\.addEventListener\('click', function\(e\) \{[\s\S]*?\n  \}\);\n  document\.getElementById\('refresh-btn'\)/, newClick + "\n  document.getElementById('refresh-btn')", 'click and translate behavior');

workflow = replaceOnce(workflow, /                  primary\['mentions'\] = len\(sources\)\n/, `                  primary['mentions'] = len(sources)\n                  source_boost = min(25, max(0, len(sources) - 1) * 6)\n                  primary['quality'] = min(100, primary.get('quality', 0) + source_boost)\n                  primary['qualityExplanation'] = 'Bewertet nach UAP-Relevanz, offiziellen Begriffen/Institutionen, Quellenanzahl und Themenbündelung.'\n`, 'source quality boost');
workflow = replaceOnce(workflow, /              return sorted\(output, key=lambda a: \(a\.get\('mentions', 1\), a\.get\('quality', 0\)\), reverse=True\)/, "              return sorted(output, key=lambda a: (a.get('quality', 0), a.get('mentions', 1)), reverse=True)", 'quality sorting');
workflow = workflow.replace('Summarize ONLY the article text below in 4 factual sentences.', 'Summarize ONLY the article text below in 6 factual sentences.');
workflow = workflow.replace('Plain English, no markdown.', 'Plain English, no markdown. Include the concrete actors, decisions, claims, evidence, and uncertainty that the article itself states.');
workflow = workflow.replace("'max_tokens': 650,", "'max_tokens': 950,");
workflow = workflow.replace("if summary == 'INSUFFICIENT_SOURCE_TEXT' or len(summary) < 120:", "if summary == 'INSUFFICIENT_SOURCE_TEXT' or len(summary) < 180:");
workflow = replaceOnce(workflow, /                      'matchedTerms': article.get\('matchedTerms', \[\]\),\n/, `                      'qualityExplanation': article.get('qualityExplanation', 'Bewertet nach UAP-Relevanz, offiziellen Begriffen/Institutionen, Quellenanzahl und Themenbündelung.'),\n                      'matchedTerms': article.get('matchedTerms', []),\n`, 'quality explanation output');

fs.writeFileSync('index.html', html);
fs.writeFileSync('.github/workflows/daily-scan.yml', workflow);
fs.writeFileSync('sw.js', sw);
console.log('Applied app feed cleanup, source-weighted quality, and longer grounded summary prompt.');
